import React, { useState, useEffect } from 'react';
import api from '../../services/api';
import { FiEdit2, FiTrash2, FiPlus } from 'react-icons/fi';

const AdminJobTitles = () => {
  const [items, setItems] = useState([]);
  const [showModal, setShowModal] = useState(false);
  const [edit, setEdit] = useState(null);
  const [form, setForm] = useState({ title: '', description: '', note: '' });

  useEffect(() => { fetchItems(); }, []);

  const fetchItems = async () => {
    const { data } = await api.get('/admin/job-titles');
    setItems(data);
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (edit) {
      await api.put(`/admin/job-titles/${edit._id}`, form);
    } else {
      await api.post('/admin/job-titles', form);
    }
    setShowModal(false); setEdit(null); setForm({ title: '', description: '', note: '' });
    fetchItems();
  };

  const handleDelete = async (id) => {
    if (window.confirm('Delete this job title?')) {
      await api.delete(`/admin/job-titles/${id}`);
      fetchItems();
    }
  };

  return (
    <div>
      <div className="toolbar">
        <div className="toolbar-right" style={{ marginLeft: 'auto' }}>
          <button className="btn btn-primary" onClick={() => { setEdit(null); setForm({ title: '', description: '', note: '' }); setShowModal(true); }}><FiPlus /> Add Job Title</button>
        </div>
      </div>
      <div className="card">
        <div className="card-header"><h3>Job Titles</h3></div>
        <div className="card-body">
          <div className="table-container">
            <table>
              <thead><tr><th>Title</th><th>Description</th><th>Note</th><th>Actions</th></tr></thead>
              <tbody>
                {items.map(item => (
                  <tr key={item._id}>
                    <td><strong>{item.title}</strong></td>
                    <td>{item.description || '-'}</td>
                    <td>{item.note || '-'}</td>
                    <td>
                      <button className="action-btn" onClick={() => { setEdit(item); setForm({ title: item.title, description: item.description, note: item.note }); setShowModal(true); }}><FiEdit2 /></button>
                      <button className="action-btn" onClick={() => handleDelete(item._id)}><FiTrash2 /></button>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      </div>
      {showModal && (
        <div className="modal-backdrop" onClick={() => setShowModal(false)}>
          <div className="modal" onClick={e => e.stopPropagation()}>
            <div className="modal-header"><h3>{edit ? 'Edit' : 'Add'} Job Title</h3><button className="close-btn" onClick={() => setShowModal(false)}>&times;</button></div>
            <form onSubmit={handleSubmit}>
              <div className="modal-body">
                <div className="form-group"><label>Title</label><input value={form.title} onChange={e => setForm({...form, title: e.target.value})} required /></div>
                <div className="form-group"><label>Description</label><textarea value={form.description} onChange={e => setForm({...form, description: e.target.value})} rows={2} /></div>
                <div className="form-group"><label>Note</label><textarea value={form.note} onChange={e => setForm({...form, note: e.target.value})} rows={2} /></div>
              </div>
              <div className="modal-footer">
                <button type="button" className="btn btn-outline" onClick={() => setShowModal(false)}>Cancel</button>
                <button type="submit" className="btn btn-primary">{edit ? 'Update' : 'Save'}</button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default AdminJobTitles;
